import{c,Q as o,j as r,m as a}from"./chunks/framework.D9IbVcwA.js";const s=JSON.parse('{"title":"x86_64 架构支持","description":"","frontmatter":{},"headers":[],"relativePath":"document/kernel/arch.md","filePath":"document/kernel/arch.md","lastUpdated":1777209094000}'),l={name:"document/kernel/arch.md"};function d(i,e,t,n,h,p){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="x86-64-架构支持" tabindex="-1">x86_64 架构支持 <a class="header-anchor" href="#x86-64-架构支持" aria-label="Permalink to &quot;x86_64 架构支持&quot;">​</a></h1><blockquote><p>里程碑: <code>009_big_kernel_entry</code> <code>010_big_kernel_gdt_idt</code> <code>011_big_kernel_pic_irq</code> <code>022_ring3_usermode</code></p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>大内核的 x86_64 架构层，包括高半核启动、GDT/IDT/TSS 初始化、中断/异常处理框架、PIC/PIT 硬件编程、用户态切换、上下文切换和系统调用入口路径。</p><h2 id="内核启动-kernel-arch-x86-64-boot-s-kernel-arch-x86-64-crt-stub-cpp" tabindex="-1">内核启动 (<code>kernel/arch/x86_64/boot.S</code>, <code>kernel/arch/x86_64/crt_stub.cpp</code>) <a class="header-anchor" href="#内核启动-kernel-arch-x86-64-boot-s-kernel-arch-x86-64-crt-stub-cpp" aria-label="Permalink to &quot;内核启动 (`kernel/arch/x86_64/boot.S`, `kernel/arch/x86_64/crt_stub.cpp`)&quot;">​</a></h2><ul><li><code>_start</code>: 切换 <code>%rsp</code> 到 <code>__kernel_stack_top</code>，清 BSS，<code>_init_global_ctors</code>，<code>call kernel_main</code></li><li>链接脚本: <code>KERNEL_VMA = 0xFFFFFFFF80000000</code>，加载地址 <code>0x1000000</code></li><li>C++ 运行时: <code>__cxa_pure_virtual</code>、<code>__stack_chk_fail</code> (均 <code>cli;hlt</code>)，<code>__cxa_atexit</code> 返回 0</li></ul><h2 id="gdt-kernel-arch-x86-64-gdt-hpp-cpp" tabindex="-1">GDT (<code>kernel/arch/x86_64/gdt.hpp/cpp</code>) <a class="header-anchor" href="#gdt-kernel-arch-x86-64-gdt-hpp-cpp" aria-label="Permalink to &quot;GDT (`kernel/arch/x86_64/gdt.hpp/cpp`)&quot;">​</a></h2><ul><li>全局 GDT: null / kernel_code64 / kernel_data64 / user_code64 / user_data64 / TSS (16 字节双槽)</li><li><code>constexpr</code> 工厂: <code>make_null/make_code64/make_data64/make_tss</code></li><li>选择子常量: <code>GDT_KERNEL_CODE=0x08</code>, <code>GDT_KERNEL_DATA=0x10</code>, <code>GDT_USER_CODE=0x1B</code>, <code>GDT_USER_DATA=0x23</code>, <code>GDT_TSS=0x28</code></li><li><code>gdt_init()</code>: 填充 + <code>lgdt</code> + <code>ltr $GDT_TSS</code></li></ul><h2 id="idt-中断-kernel-arch-x86-64-idt-hpp-cpp-interrupts-s" tabindex="-1">IDT &amp; 中断 (<code>kernel/arch/x86_64/idt.hpp/cpp</code>, <code>interrupts.S</code>) <a class="header-anchor" href="#idt-中断-kernel-arch-x86-64-idt-hpp-cpp-interrupts-s" aria-label="Permalink to &quot;IDT &amp; 中断 (`kernel/arch/x86_64/idt.hpp/cpp`, `interrupts.S`)&quot;">​</a></h2><ul><li>256 个 ISR stub: <code>isr_noerr</code> (推 0 + vec) / <code>isr_err</code> (推 vec)</li><li><code>InterruptFrame</code>: <code>r15..rax + vector + error_code + rip/cs/rflags/rsp/ss</code></li><li><code>using IRQHandler = void(*)(InterruptFrame*)</code></li><li><code>idt_set_handler(vector, handler)</code> / <code>idt_init()</code></li><li><code>isr_common</code>: 保存 r15..rax，<code>call isr_dispatch</code>，恢复，<code>iretq</code></li><li>有 error code 的向量: 8/10/11/12/13/14/17/21</li></ul><h2 id="异常处理-kernel-arch-x86-64-exception-handlers-cpp" tabindex="-1">异常处理 (<code>kernel/arch/x86_64/exception_handlers.cpp</code>) <a class="header-anchor" href="#异常处理-kernel-arch-x86-64-exception-handlers-cpp" aria-label="Permalink to &quot;异常处理 (`kernel/arch/x86_64/exception_handlers.cpp`)&quot;">​</a></h2><ul><li><code>dump_registers(InterruptFrame*)</code>: 格式化输出所有寄存器</li><li><code>handle_pf</code>: 读 <code>%cr2</code>，解析页错误码</li><li><code>handle_gp</code>: General Protection Fault</li><li><code>handle_df [[noreturn]]</code>: Double Fault</li></ul><h2 id="tss-kernel-arch-x86-64-tss-hpp" tabindex="-1">TSS (<code>kernel/arch/x86_64/tss.hpp</code>) <a class="header-anchor" href="#tss-kernel-arch-x86-64-tss-hpp" aria-label="Permalink to &quot;TSS (`kernel/arch/x86_64/tss.hpp`)&quot;">​</a></h2><ul><li><code>TSS [[gnu::packed]]</code>: RSP[3], IST[7], IOPB offset</li><li>IST1 指向独立 4KB Double Fault 栈</li><li><code>tss_set_rsp0(kernel_stack_top)</code>: 每次 task 切换调用</li></ul><h2 id="pic-kernel-arch-x86-64-pic-hpp-cpp" tabindex="-1">PIC (<code>kernel/arch/x86_64/pic.hpp/cpp</code>) <a class="header-anchor" href="#pic-kernel-arch-x86-64-pic-hpp-cpp" aria-label="Permalink to &quot;PIC (`kernel/arch/x86_64/pic.hpp/cpp`)&quot;">​</a></h2><ul><li><code>PIC::init(master_offset=0x20, slave_offset=0x28)</code>: ICW1-ICW4 + <code>io_wait()</code></li><li>重映射: IRQ0-7 → 0x20-0x27, IRQ8-15 → 0x28-0x2F</li><li><code>PIC::send_eoi(irq)</code> / <code>PIC::mask(irq)</code> / <code>PIC::unmask(irq)</code> / <code>PIC::disable_all()</code></li></ul><h2 id="用户态切换-kernel-arch-x86-64-usermode-s" tabindex="-1">用户态切换 (<code>kernel/arch/x86_64/usermode.S</code>) <a class="header-anchor" href="#用户态切换-kernel-arch-x86-64-usermode-s" aria-label="Permalink to &quot;用户态切换 (`kernel/arch/x86_64/usermode.S`)&quot;">​</a></h2><ul><li><code>jump_to_usermode(entry, user_stack, arg)</code>: 配置 STAR MSR，<code>%rcx=entry</code>，<code>%rsp=user_stack</code>，<code>%rdi=arg</code>，<code>swapgs</code>，<code>sysretq</code></li><li>用户态 ELF 链接到 <code>0x400000</code></li><li>用户栈在 <code>0x7FFFFF000</code> 附近</li></ul><h2 id="上下文切换-kernel-arch-x86-64-context-switch-s" tabindex="-1">上下文切换 (<code>kernel/arch/x86_64/context_switch.S</code>) <a class="header-anchor" href="#上下文切换-kernel-arch-x86-64-context-switch-s" aria-label="Permalink to &quot;上下文切换 (`kernel/arch/x86_64/context_switch.S`)&quot;">​</a></h2><ul><li><code>context_switch(CpuContext* from, CpuContext* to)</code></li><li>保存 callee-saved: r15/r14/r13/r12/rbp/rbx/rsp + rip (leaq .restore)</li><li>恢复 to 的对应字段，<code>jmp *56(%rsi)</code></li></ul><h2 id="i-o-原语-kernel-arch-x86-64-io-hpp" tabindex="-1">I/O 原语 (<code>kernel/arch/x86_64/io.hpp</code>) <a class="header-anchor" href="#i-o-原语-kernel-arch-x86-64-io-hpp" aria-label="Permalink to &quot;I/O 原语 (`kernel/arch/x86_64/io.hpp`)&quot;">​</a></h2><ul><li>内联汇编: <code>io_inb/io_outb/io_inw/io_outw/io_inl/io_outl/io_wait</code>，<code>&quot;memory&quot;</code> clobber</li></ul><h2 id="内存布局-kernel-arch-x86-64-memory-layout-hpp" tabindex="-1">内存布局 (<code>kernel/arch/x86_64/memory_layout.hpp</code>) <a class="header-anchor" href="#内存布局-kernel-arch-x86-64-memory-layout-hpp" aria-label="Permalink to &quot;内存布局 (`kernel/arch/x86_64/memory_layout.hpp`)&quot;">​</a></h2><ul><li>统一内核虚拟内存布局: KMEM_HEAP / MMIO / STACK / DMA / EXT2_DMA</li><li>所有区域通过 base + size 计算</li></ul><h2 id="分页-kernel-arch-x86-64-paging-hpp" tabindex="-1">分页 (<code>kernel/arch/x86_64/paging.hpp</code>) <a class="header-anchor" href="#分页-kernel-arch-x86-64-paging-hpp" aria-label="Permalink to &quot;分页 (`kernel/arch/x86_64/paging.hpp`)&quot;">​</a></h2><ul><li><code>union PageEntry {uint64_t raw; struct{present,writable,user,...,addr:40,nx}}</code></li><li><code>FLAG_PRESENT/WRITABLE/USER/NX</code> 常量</li></ul><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>kernel/arch/x86_64/boot.S</code> — 内核入口</li><li><code>kernel/arch/x86_64/gdt.hpp/cpp</code> — GDT</li><li><code>kernel/arch/x86_64/idt.hpp/cpp</code> — IDT</li><li><code>kernel/arch/x86_64/interrupts.S</code> — ISR stubs</li><li><code>kernel/arch/x86_64/exception_handlers.cpp</code> — 异常处理</li><li><code>kernel/arch/x86_64/pic.hpp/cpp</code> — PIC</li><li><code>kernel/arch/x86_64/tss.hpp</code> — TSS</li><li><code>kernel/arch/x86_64/usermode.S</code> — 用户态切换</li><li><code>kernel/arch/x86_64/context_switch.S</code> — 上下文切换</li><li><code>kernel/arch/x86_64/io.hpp</code> — I/O 原语</li><li><code>kernel/arch/x86_64/paging.hpp</code> — 页表项</li><li><code>kernel/arch/x86_64/memory_layout.hpp</code> — 内存布局</li><li><code>kernel/arch/x86_64/crt_stub.cpp</code> — C++ 运行时</li></ul>',28)])])}const x=c(l,[["render",d]]);e